1	'use strict';
2	/**
3	 * coverage-contract.js - coverage as BLOCKING DATA, not reporting theatre (caution.md C-029).
4	 *
5	 * The reconciliation gate used to check "was the site reachable", not "did we read the page the rule
6	 * needs", so absence rules fired on pages nobody read. Here every catalogue rule declares the page-class
7	 * its website obligations need, and coverageFor() answers per rule: `covered` (that class was crawled) or
8	 * `screened` (it was not; NEVER a breach input). Wave-2 treats `screened` as a HARD BLOCK: no screened
9	 * rule may become a breach.
10	 *
11	 * classify() (caution.md C-044) matches PATH SEGMENTS with anchored tokens, never loose substrings, so
12	 * /feedback does not credit 'fees', /cost-of-living does not credit 'pricing', /returning-customers does
13	 * not credit 'returns'. Pure and deterministic: no network, no clock, no env.
14	 *
15	 * The absence-demotion interlock (caution.md C-024/C-033): a rule whose evidence would be an ABSENCE claim
16	 * is demoted to `screened` (needs-review) when the corpus was truncated, and any page-class that exists
17	 * only inside an unparsed document (evidence/documents 'no-parser') is treated as NOT covered.
18	 */
19	
20	const BASE_REQUIRED = ['homepage', 'privacy'];
21	const SECTOR_REQUIRED = {
22	  'law-firms': ['complaints', 'pricing'], barristers: ['complaints'], finance: ['terms'],
23	  insurance: ['terms'], ecommerce: ['terms', 'returns'], retail: ['terms'],
24	  healthcare: ['privacy'], 'real-estate': ['fees'],
25	};
26	
27	function requiredClasses(sector) {
28	  const extra = SECTOR_REQUIRED[String(sector || '').toLowerCase()] || [];
29	  return [...new Set([...BASE_REQUIRED, ...extra])];
30	}
31	
32	// classify(page) -> the page-class of a fetched URL by PATH SEGMENT with anchored tokens (C-044). Accepts
33	// a page object ({url}|{type}) or a bare string.
34	function classify(page) {
35	  const raw = String((page && (page.url || page.type || page)) || '').toLowerCase();
36	  const path = raw.replace(/^https?:\/\/[^/]+/, '');
37	  const seg = '/' + path.replace(/[?#].*$/, '').replace(/^\/+/, ''); // normalised path, leading slash
38	  const has = (re) => re.test(seg);
39	  if (has(/\b(privacy|data[-_ ]?protection|gdpr|cookie)\b/)) return 'privacy';
40	  if (has(/\b(complaints?|ombudsman)\b/)) return 'complaints';
41	  if (has(/\bfees?\b/)) return 'fees';
42	  if (has(/\b(pricing|prices?|tariff|cost[-_ ]?(of[-_ ]?service|guide|schedule)?|charges)\b/) && !/\bcost[-_ ]?of[-_ ]?living\b/.test(seg)) return 'pricing';
43	  if (has(/\b(terms|t-and-c|conditions)\b/)) return 'terms';
44	  if (has(/\b(returns?|refunds?)\b/)) return 'returns';
45	  if (/^\/?$/.test(seg) || has(/\b(home|index)\b/)) return 'homepage';
46	  return 'other';
47	}
48	
49	// fetchedClassSet(crawledPages) -> the Set of page-classes present in the crawl. The homepage counts as
50	// present whenever ANY page was read (you always land somewhere), and 'any' is the general-corpus class.
51	function fetchedClassSet(crawledPages) {
52	  const set = new Set((crawledPages || []).map(classify));
53	  if ((crawledPages || []).length) { set.add('homepage'); set.add('any'); }
54	  return set;
55	}
56	
57	// computeCoverage(crawledPages, sector, opts) -> site-level tri-state: 'assessable' (enough required
58	// classes) or 'screened' (too little coverage -> not-assessed, never a breach on unread content).
59	function computeCoverage(crawledPages, sector, opts = {}) {
60	  const required = requiredClasses(sector);
61	  const fetched = fetchedClassSet(crawledPages);
62	  const missing = required.filter((c) => !fetched.has(c));
63	  const ratio = required.length ? (required.length - missing.length) / required.length : 0;
64	  const threshold = typeof opts.threshold === 'number' ? opts.threshold : 0.5;
65	  const reachable = (crawledPages || []).length > 0;
66	  const render_class = (!reachable || ratio < threshold) ? 'screened' : 'assessable';
67	  return { required, fetched_classes: [...fetched].sort(), missing, ratio: Math.round(ratio * 100) / 100, render_class, reachable };
68	}
69	
70	// pageClassForObligation(obligation) -> the crawl page-class an on-page presence/absence duty needs,
71	// derived from anchored tokens in the duty + element text; 'any' when the duty is a general on-page
72	// requirement (assessable on the homepage/footer). register/behavioural duties return null (their
73	// evidence comes from the registers/browser lanes, not the crawl).
74	function pageClassForObligation(obligation) {
75	  const et = obligation && obligation.evidence_type;
76	  if (et !== 'presence' && et !== 'absence') return null;
77	  const text = ((obligation.duty || '') + ' ' + (obligation.elements || []).join(' ')).toLowerCase();
78	  if (/\b(privacy|data protection|gdpr|cookie|personal data)\b/.test(text)) return 'privacy';
79	  if (/\b(complaint|ombudsman|redress)\b/.test(text)) return 'complaints';
80	  if (/\bfees?\b/.test(text)) return 'fees';
81	  if (/\b(pricing|price|tariff|charges|cost of service)\b/.test(text)) return 'pricing';
82	  if (/\b(terms|conditions)\b/.test(text)) return 'terms';
83	  if (/\b(returns?|refunds?)\b/.test(text)) return 'returns';
84	  return 'any';
85	}
86	
87	// ruleNeeds(rule) -> { needs: [pageClass...], laneOnly: bool, hasAbsence: bool }. laneOnly means the rule
88	// has NO on-page text obligation (its evidence is register/behavioural), so the crawl does not gate it.
89	function ruleNeeds(rule) {
90	  const obligations = (rule && rule.website_obligations) || [];
91	  const needs = new Set();
92	  let hasAbsence = false;
93	  for (const o of obligations) {
94	    const cls = pageClassForObligation(o);
95	    if (cls) needs.add(cls);
96	    if (o && o.evidence_type === 'absence') hasAbsence = true;
97	  }
98	  return { needs: [...needs], laneOnly: needs.size === 0, hasAbsence };
99	}
100	
101	// judgeRule(rule, fetched, ctx) -> the per-rule coverage verdict. `ctx` carries the interlock inputs:
102	// truncated (C-024) and unparsedClasses (C-033).
103	function judgeRule(rule, fetched, ctx) {
104	  const { needs, laneOnly, hasAbsence } = ruleNeeds(rule);
105	  if (laneOnly) return { id: rule.id, state: 'covered', needs: [], missing: [], reason: 'non-crawl-evidence (register/behavioural lane)' };
106	  const missing = needs.filter((c) => c !== 'any' && !fetched.has(c));
107	  const reasons = missing.map((c) => (ctx.unparsedClasses.has(c)
108	    ? 'page-class "' + c + '" lives only in an unparsed document (C-033)'
109	    : 'missing page-class "' + c + '"'));
110	  if (ctx.truncated && hasAbsence) reasons.push('absence claim on a truncated corpus demoted to needs-review (C-024)');
111	  const covered = reasons.length === 0;
112	  return { id: rule.id, state: covered ? 'covered' : 'screened', needs, missing, reason: covered ? 'all needed page-classes crawled' : reasons.join('; ') };
113	}
114	
115	// coverageFor(rules, crawledPages, opts) -> { rules:[{id,state,needs,missing,reason}], summary } where
116	// state is covered|screened per rule. `opts.truncated` and `opts.unparsedClasses` drive the interlock.
117	function coverageFor(rules, crawledPages, opts = {}) {
118	  const fetched = fetchedClassSet(crawledPages);
119	  const ctx = {
120	    truncated: Boolean(opts.truncated),
121	    unparsedClasses: opts.unparsedClasses instanceof Set ? opts.unparsedClasses : new Set(opts.unparsedClasses || []),
122	  };
123	  const out = (rules || []).map((r) => judgeRule(r, fetched, ctx));
124	  const screened = out.filter((r) => r.state === 'screened').length;
125	  return { rules: out, summary: { total: out.length, covered: out.length - screened, screened } };
126	}
127	
128	// isScreened(coverage, ruleId) -> true when wave-2 must NOT emit a breach for this rule (hard block).
129	function isScreened(coverage, ruleId) {
130	  const r = coverage && coverage.rules && coverage.rules.find((x) => x.id === ruleId);
131	  return Boolean(r) && r.state === 'screened';
132	}
133	
134	// applyCoverage(findings, coverage) -> drop breach ('miss') findings when the SITE coverage is screened.
135	function applyCoverage(findings, coverage) {
136	  if (!coverage || coverage.render_class === 'assessable') return findings || [];
137	  return (findings || []).filter((f) => f && f.status !== 'miss');
138	}
139	
140	module.exports = {
141	  BASE_REQUIRED, SECTOR_REQUIRED, requiredClasses, classify, computeCoverage,
142	  coverageFor, isScreened, applyCoverage, pageClassForObligation, ruleNeeds,
143	};
144

1	const { htmlToText } = require('../../../lib/util/html-text.js');
2	const { isNonCrawlable } = require('../../../lib/util/url-safe.js');
3	// Compliance scanner · Phase 6 task 6.2.4
4	// Loads compliance_rules per the jurisdiction-router output for (country, sector).
5	// For each rule, runs regex_pattern + url_check against home and standard policy pages.
6	// Returns hits (rule satisfied), misses (rule failed), partials.
7	// Every finding carries: rule_id, framework_short, severity, citation_url, evidence URL + snippet.
8	
9	const path = require('path');
10	const fs = require('fs');
11	const { execFileSync } = require('child_process');
12	const _crypto = require('crypto');
13	// E-252 (v23.0): getCached / writeCache are NO LONGER IMPORTED. The scan cache is gone permanently.
14	const { fetchWithRetry } = require('../lib/http.js');
15	const { routeJurisdictions, normaliseSector: normaliseSectorAlias } = require('../../../lib/compliance/jurisdiction-router.js');
16	const { buildCorpusIndex, scanRuleGlobal, isNegated } = require('./corpus-index.js'); // B2 — every-page/every-word matcher
17	const SCANNER = 'compliance';
18	
19	const ROOT = path.resolve(__dirname, '..', '..', '..', '..');
20	function pgPath() { return path.resolve(ROOT, 'scripts', 'psql'); }
21	function pg(sql) {
22	  const url = process.env.NEON_URL || process.env.NEON_CONNECTION_STRING;
23	  if (!url) return null;
24	  try { return execFileSync(pgPath(), [url, '-tA', '-c', sql], { encoding: 'utf8' }).toString().trim(); } catch (_e) { /* FAIL-OPEN: a parse/probe guard — the default IS the answer, no failure is being hidden. */ return null; }
25	}
26	
27	// B1 — the merged canonical law repo (committed seed), indexed framework_short → law. Lazy + cached in-process so
28	// the resolver overlay adds no per-mint DB round-trip (throughput-safe). null if the seed is missing (overlay no-ops).
29	let _CANON_IDX;
30	function canonicalIndex() {
31	  if (_CANON_IDX !== undefined) return _CANON_IDX;
32	  try {
33	    const laws = JSON.parse(fs.readFileSync(path.join(ROOT, 'db', 'seeds', 'compliance-laws.json'), 'utf8'));
34	    const m = new Map();
35	    for (const l of laws) for (const t of String(l.neon_framework_short || '').split(',').map(s => s.trim()).filter(Boolean)) if (!m.has(t)) m.set(t, l);
36	    _CANON_IDX = m;
37	  } catch (_e) { _swarn('compliance.js:37', _e); _CANON_IDX = null; }
38	  return _CANON_IDX;
39	}
40	
41	// B3 — recent enforcement records (populated by scripts/enforcement-sync.js) for the per-breach panel. ONE query
42	// per scan, cheap, throughput-safe; returns [] gracefully if the table isn't provisioned yet (panel stays honest).
43	let _enfTableOk; // cached: is compliance_enforcement provisioned? avoids a failing query (+stderr noise) every scan
44	function loadEnforcement(jurisdictions) {
45	  if (_enfTableOk === undefined) { const chk = pg("SELECT (to_regclass('public.compliance_enforcement') IS NOT NULL)::text;"); _enfTableOk = !!(chk && /^t/i.test(chk.trim())); }
46	  if (!_enfTableOk) return [];
47	  const js = [...new Set((jurisdictions || []).concat(['GLOBAL']))].filter(Boolean).map(j => `'${String(j).replace(/'/g, "''")}'`).join(',');
48	  if (!js) return [];
49	  const sql = `SELECT COALESCE(json_agg(row_to_json(t)),'[]') FROM (SELECT matched_law_ids,jurisdiction,breach_type,entity_named,penalty,ruling_date::text AS ruling_date,one_line_summary,source_url,source_feed,classifier FROM compliance_enforcement WHERE jurisdiction IN (${js}) ORDER BY ruling_date DESC NULLS LAST LIMIT 500) t;`;
50	  const raw = pg(sql);
51	  if (!raw) return [];
52	  try { return JSON.parse(raw); } catch (_e) { /* FAIL-OPEN: a parse/probe guard — the default IS the answer, no failure is being hidden. */ return []; }
53	}
54	
55	// E31 — THE THREE-NUMBER DOCTRINE. The rail was rendering "15 frameworks screened · 15 bind you", because the
56	// renderer's `frameworksTotal` WAS the binding count. That erases the screening story, which is the entire
57	// differentiator: we screen a whole register and tell you the few that actually attach. It also made the body copy
58	// say "all 18 frameworks", contradicting the site's own claim, and undersold a 672-rule engine by a factor of forty.
59	// Three numbers, measured not guessed, emitted here so the renderer can never conflate them again:
60	//   catalogue_frameworks - every framework in the live register
61	//   catalogue_rules      - every ACTIVE rule in the live register
62	//   rules_evaluated      - the page-level checks actually executed on this firm's binding set
63	// THE WARNING SINK (see build.js). 17 silent swallows lived in this file - the scanner that decides what we ACCUSE
64	// a law firm of. A swallowed error here means a check quietly did not run and the audit still claimed a clean bill.
65	// The adjudicator threw "cc is not defined" inside one of these for two whole engine versions.
66	const _SWARN = [];
67	// SUB-STAGE LEDGER. cookie_evidence, ico_register and statute_rag all run INSIDE this scanner, so build.js
68	// cannot see them and the stage manifest reported them 'not_reached' forever — while the PECR breach they
69	// produce was sitting in the payload. A manifest that lies by omission is worse than no manifest.
70	const _SUBSTAGE = {};
71	function _stage(name, state, reason) { _SUBSTAGE[name] = { state, reason: reason || null }; }
72	
73	function _swarn(where, e) {
74	  const msg = String((e && e.message) || e || 'unknown').slice(0, 180);
75	  _SWARN.push({ where, error: msg });
76	  console.error('[scan-warn] ' + where + ': ' + msg);
77	}
78	
79	let _catCache = null;
80	function catalogueSize() {
81	  if (_catCache) return _catCache;
82	  try {
83	    // pg() returns tab-delimited rows, exactly as loadRules() consumes them.
84	    const raw = pg('SELECT count(*)::int, count(DISTINCT framework_short)::int FROM compliance_rules WHERE active');
85	    const [rules, frameworks] = String(raw || '').trim().split('\t').map((n) => parseInt(n, 10));
86	    _catCache = {
87	      catalogue_rules: Number.isFinite(rules) ? rules : null,
88	      catalogue_frameworks: Number.isFinite(frameworks) ? frameworks : null,
89	    };
90	  } catch (_e) { _swarn('compliance.js:84', _e);
91	    _catCache = { catalogue_rules: null, catalogue_frameworks: null };   // fail-open: NEVER invent a count
92	  }
93	  return _catCache;
94	}
95	
96	function loadRules({ frameworks }) {
97	  if (!frameworks.length) return [];
98	  const inList = frameworks.map(f => `'${f.replace(/'/g, "''")}'`).join(',');
99	  const sql = `
100	    SELECT id, framework_short, rule_id, description, regex_pattern, url_check, severity, citation_url,
101	           COALESCE(rule_type, 'must_appear') AS rule_type,
102	           COALESCE(trigger_pattern, '') AS trigger_pattern,
103	           COALESCE(array_to_string(sector_relevance, '|'), '') AS sectors,
104	           COALESCE(fine_low_gbp::text, '') AS fine_low,
105	           COALESCE(fine_high_gbp::text, '') AS fine_high,
106	           COALESCE(layman_explanation, '') AS layman,
107	           COALESCE(tamazia_fix_short, '') AS tamazia_fix,
108	           COALESCE(service_page_path, '/services/regulatory-compliance/') AS service_page_path,
109	           COALESCE(pricing_tier, 'Authority') AS pricing_tier,
110	           COALESCE(enforcement_example, '') AS enforcement_example,
111	           COALESCE(penalty_basis, '') AS penalty_basis,
112	           COALESCE(penalty_note, '') AS penalty_note,
113	           COALESCE(enforce_typical_low_gbp::text,'') AS enf_low,
114	           COALESCE(enforce_typical_high_gbp::text,'') AS enf_high,
115	           COALESCE(enforce_methodology,'') AS enf_method,
116	           COALESCE(enforce_context,'') AS enf_ctx,
117	           COALESCE(enforce_max_rare::text,'') AS enf_rare,
118	           COALESCE(statutory_citation,'') AS stat_cite,
119	           COALESCE(check_style,'') AS check_style,
120	           COALESCE(regex_elements::text,'') AS regex_elements,
121	           COALESCE(page_scope,'') AS page_scope
122	    FROM compliance_rules
123	    WHERE framework_short IN (${inList}) AND active = TRUE
124	    ORDER BY CASE severity WHEN 'P0' THEN 0 WHEN 'P1' THEN 1 ELSE 2 END, framework_short, rule_id`;
125	  const raw = pg(sql);
126	  if (!raw) return [];
127	  return raw.split('\n').filter(Boolean).map(line => {
128	    const [id, fw, rid, desc, pat, urlCheck, sev, cite, ruleType, triggerPat, sectorsStr, fineLow, fineHigh, layman, tamaziaFix, svcPath, tier, enforcement, penaltyBasis, penaltyNote, enfLow, enfHigh, enfMethod, enfCtx, enfRare, statCite, checkStyle, regexElements, pageScope] = line.split('\t');
129	    return {
130	      id: Number(id), framework_short: fw, rule_id: rid, description: desc,
131	      regex_pattern: pat === '' || pat === 'NULL' ? null : pat,
132	      url_check: urlCheck === '' || urlCheck === 'NULL' ? null : urlCheck,
133	      severity: sev, citation_url: cite,
134	      rule_type: ruleType || 'must_appear',
135	      trigger_pattern: triggerPat || null,
136	      sectors: sectorsStr ? sectorsStr.split('|').filter(Boolean) : [],
137	      fine_low_gbp: fineLow ? Number(fineLow) : null,
138	      fine_high_gbp: fineHigh ? Number(fineHigh) : null,
139	      layman_explanation: layman || null,
140	      tamazia_fix_short: tamaziaFix || null,
141	      service_page_path: svcPath || '/services/regulatory-compliance/',
142	      pricing_tier: tier || 'Authority',
143	      enforcement_example: enforcement && enforcement !== 'NULL' ? enforcement : null,
144	      penalty_basis: penaltyBasis && penaltyBasis !== 'NULL' ? penaltyBasis : null,
145	      penalty_note: penaltyNote && penaltyNote !== 'NULL' ? penaltyNote : null,
146	      enforce_typical_low_gbp: enfLow ? Number(enfLow) : null,
147	      enforce_typical_high_gbp: enfHigh ? Number(enfHigh) : null,
148	      enforce_methodology: enfMethod || null,
149	      enforce_context: enfCtx || null,
150	      enforce_max_rare: enfRare === 't' || enfRare === 'true',
151	      statutory_citation: statCite || null,
152	      check_style: checkStyle && checkStyle !== 'NULL' ? checkStyle : null,
153	      regex_elements: (() => { try { return regexElements && regexElements !== '' && regexElements !== 'NULL' ? JSON.parse(regexElements) : null; } catch (_e) { /* FAIL-OPEN: a parse/probe guard — the default IS the answer, no failure is being hidden. */ return null; } })(),
154	      page_scope: pageScope && pageScope !== 'NULL' ? (pageScope || null) : null
155	    };
156	  });
157	}
158	
159	// Phase 7.4 · broader path coverage so we trigger on operating-jurisdiction language found on /global, /locations, /careers, /investors, /press, /sustainability, etc.
160	const POLICY_PATHS = [
161	  '/', '/privacy', '/privacy-policy', '/cookies', '/cookie-policy', '/cookie-settings',
162	  '/terms', '/terms-and-conditions', '/legal', '/contact', '/about', '/about-us',
163	  // Regulatory/professional-body disclosure pages (SRA/BSB/CQC/GMC/FCA 'authorised and regulated by' text lives here on
164	  // large firms, not the homepage): law firms + regulated professions publish it on a dedicated legal-notices page.
165	  '/legal-notices', '/legal-notice', '/regulatory-information', '/regulatory', '/regulatory-notices', '/disclaimer',
166	  '/legal-and-regulatory', '/terms-of-use', '/complaints', '/complaints-procedure', '/compliance', '/regulatory-disclosures',
167	  '/careers', '/case-studies', '/news', '/press', '/investors', '/sustainability',
168	  '/security', '/accessibility', '/global', '/locations', '/offices', '/team',
169	  '/leadership', '/clients', '/services', '/sectors', '/markets', '/regions',
170	  '/why-us', '/work', '/insights', '/blog',
171	  // Phase 3a — fee/pricing/checkout pages (the SRA price-transparency / consumer drip-pricing surface) that were
172	  // never guessed before, so element-checklist rules can assess the page they actually live on.
173	  '/fees', '/our-fees', '/pricing', '/prices', '/price', '/costs', '/fees-and-pricing',
174	  '/fees-pricing', '/our-pricing', '/pricing-and-fees', '/tariff', '/quote', '/get-a-quote',
175	  '/checkout', '/cart', '/basket', '/book', '/booking',
176	  // EU-language policy paths (i18n): French/German/Italian/Spanish/Dutch sites publish their privacy/legal notices
177	  // under localised paths, so an English-only path list never reads the EU privacy policy -> false 'missing GDPR
178	  // disclosure' cascade on compliant EU sites. (sector-audit i18n fix)
179	  '/confidentialite', '/confidentialite/', '/politique-de-confidentialite', '/politique-confidentialite',
180	  '/mentions-legales', '/rgpd', '/donnees-personnelles', '/vie-privee', '/cookies-fr',
181	  '/datenschutz', '/datenschutzerklaerung', '/datenschutzerklarung', '/impressum', '/dsgvo', '/rechtliches',
182	  '/privacy-it', '/privacidad', '/aviso-legal', '/privacybeleid', '/juridisch'
183	];
184	
185	function _sameHost(u, domain) {
186	  try { const h = new URL(u).hostname.replace(/^www\./, ''); return h === domain.replace(/^www\./, ''); } catch (_e) { /* FAIL-OPEN: a parse/probe guard — the default IS the answer, no failure is being hidden. */ return false; }
187	}
188	// A1 — registrable-domain (eTLD+1) so SUBDOMAINS (blog./help./property./uk.) and the www variant all count as the
189	// SAME SITE and get crawled. Covers the common multi-part public suffixes; defaults to last-two-labels otherwise.
190	const _MULTI_TLD = new Set(['co.uk', 'org.uk', 'gov.uk', 'ac.uk', 'me.uk', 'ltd.uk', 'plc.uk', 'net.uk', 'sch.uk', 'nhs.uk', 'com.au', 'net.au', 'org.au', 'edu.au', 'gov.au', 'co.nz', 'org.nz', 'govt.nz', 'co.za', 'org.za', 'com.sg', 'edu.sg', 'gov.sg', 'com.br', 'com.mx', 'co.in', 'net.in', 'org.in', 'co.jp', 'or.jp', 'com.hk', 'com.cn', 'co.ae', 'gov.ae', 'com.tr', 'co.il', 'com.sa']);
191	function _registrable(host) {
192	  host = String(host || '').toLowerCase().replace(/^www\./, '').replace(/:.*$/, '');
193	  const p = host.split('.');
194	  if (p.length <= 2) return host;
195	  return _MULTI_TLD.has(p.slice(-2).join('.')) ? p.slice(-3).join('.') : p.slice(-2).join('.');
196	}
197	// Same registrable site (input domain ∪ any extra accepted hosts, e.g. a detected canonical alternate domain).
198	function _sameSite(u, accepted) {
199	  try { return accepted.has(_registrable(new URL(u).hostname)); } catch (_e) { /* FAIL-OPEN: a parse/probe guard — the default IS the answer, no failure is being hidden. */ return false; }
200	}
201	// The firm's CANONICAL host when the crawled domain is just an alias/landing shell that 404s its own sub-paths
202	// (e.g. taylorrose.co.uk → taylor-rose.co.uk). Read <link rel=canonical>/og:url, else the host the homepage's nav
203	// links point at most. Returns a host string of a DIFFERENT registrable domain, or null.
204	function _canonicalAltHost(html, domain) {
205	  const inReg = _registrable(domain);
206	  const tryUrls = [];
