// fetchHomepage(opts, base, perPageMs, record) -> { home, homeHtml, homeKlass }. The homepage is the one
// mandatory surface (footer disclosures live here, C-034); a non-content homepage (login/challenge/error/
// SPA shell) is recorded and never asserted from (C-031/C-038).
async function fetchHomepage(opts, base, perPageMs, record) {
  const home = await fetchPage(opts.fetchFn, base + '/', perPageMs, opts.timers);
  const homeHtml = home && home.body ? String(home.body) : '';
  const homeKlass = extract.pageContentClass(home ? home.status : 0, homeHtml);
  if (homeKlass !== 'content') record('homepage-not-content', base + '/ classified as "' + homeKlass + '"; no content asserted from it (C-031/C-038)');
  return { home, homeHtml, homeKlass };
}

// discoverFetchList(opts, dom, base, accepted, homeHtml, fetchXml, maxPages) -> the deduped, same-site,
// Tier-1-FIRST-then-capped fetch list (C-026). Links (homepage) and sitemap are discovered in PARALLEL
// (E-236); orderCandidates ranks by tier BEFORE the cap slice, so a Tier-1 legal page survives a cap
// smaller than the candidate count even when it was discovered last.
async function discoverFetchList(opts, dom, base, accepted, homeHtml, fetchXml, maxPages) {
  const [links, sitemap] = await Promise.all([
    Promise.resolve(homeHtml ? discover.discoverLinks(homeHtml, base, accepted) : []),
    discover.discoverSitemap(dom, accepted, fetchXml).catch(() => []),
  ]);
  return discover.orderCandidates(base + '/', [...links, ...sitemap], accepted, maxPages);
}

// followFooterDocuments(opts, homeHtml, base, accepted, pages, perPageMs, record) -> the documents-lane
// result. Skipped (empty) when document-following is disabled or nothing readable was crawled; otherwise
// footer-linked policy documents are followed and read honestly (C-033, evidence/documents).
async function followFooterDocuments(opts, homeHtml, base, accepted, pages, perPageMs, record) {
  const empty = { documents: [], unparsed: [], unparsedClasses: new Set(), notes: [] };
  if (opts.followDocuments === false || !pages.length) return empty;
  return collectDocuments(footerLinks(homeHtml, base, accepted),
    { fetchFn: opts.fetchFn, deadlineMs: perPageMs, timers: opts.timers, log: record });
}

// crawl(domain, opts) -> the evidence bundle. Thin orchestrator: resolve budgets, fetch the homepage,
// discover links + sitemap in parallel, order Tier-1-first then cap, fetch the corpus in parallel, follow
// footer documents, and assemble the corpus + coverage report.

