// patternsFromElement(elementText, evidenceType, pageClass) -> { patterns, unpatternable }. A quoted
// phrase becomes an anchored-regex (highest precision); otherwise a salient token-set; a findability
// element also yields a url-path from its page-class. An element that reduces to nothing distinctive is
// returned as unpatternable (propose.js abstains rather than fire a low-precision pattern - the C-049
// "mute or over-broad" trap avoided by refusing to guess).
function patternsFromElement(elementText, evidenceType, pageClass) {
  const guarded = evidenceType === 'absence';
  const patterns = [];
  for (const phrase of quotedSpans(elementText)) {
    const src = buildAnchoredRegex(phrase);
    if (src) patterns.push({ kind: 'anchored-regex', value: src, negation_guarded: guarded });
  }
  if (!patterns.length) {
    const tokens = salientTokens(elementText);
    if (tokens.length) {
      patterns.push({ kind: 'token-set', value: { tokens, mode: 'all' }, negation_guarded: guarded });
    }
  }
  if (pageClass && pageClass !== 'any' && FINDABILITY_RX.test(elementText)) {
    patterns.push({ kind: 'url-path', value: '/' + pageClass, negation_guarded: false });
  }
  return { patterns, unpatternable: patterns.length === 0 };
}

